(()=>{"use strict";window.scanGoogleDrive=async function(o){try{console.log("🔍 Сканируем папку:",o);let n=null;const s=o.match(/\/folders\/([a-zA-Z0-9_-]+)/);if(s)n=s[1];else{const e=o.match(/id=([a-zA-Z0-9_-]+)/);e&&(n=e[1])}if(!n)throw new Error("Не удалось извлечь ID папки из ссылки");console.log("📁 ID папки:",n);const t=`https://www.googleapis.com/drive/v3/files?q='${n}'+in+parents&key=${AIzaSyAKtOvwvOQOBsGy4vFi_HmSN6U33WcWcbE}&fields=files(id,name,mimeType)&corpora=user`;console.log("📡 Отправляем запрос к Google API...");const l=await fetch(t);if(!l.ok){var e;const o=await l.json();throw console.error("❌ Ошибка API:",o),new Error(`Ошибка API: ${l.status} - ${(null===(e=o.error)||void 0===e?void 0:e.message)||"Неизвестная ошибка"}`)}const r=(await l.json()).files||[];console.log("📁 Найдено файлов:",r.length);const i=r.filter(o=>o.name.toLowerCase().endsWith(".mp3")||"audio/mpeg"===o.mimeType);return console.log("🎵 MP3 файлов:",i.length),i.forEach(o=>{console.log("  -",o.name,"(ID:",o.id,")")}),i.map(o=>({id:o.id,name:o.name,title:o.name.replace(/\.mp3$/i,"").replace(/[_-]/g," "),file:`https://drive.google.com/uc?export=download&id=${o.id}`}))}catch(o){throw console.error("❌ Ошибка при сканировании:",o),o}}})();
